package com.example.cms.project.schedule; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class ProjectScheduleService { private final JdbcTemplate jdbc; public ProjectScheduleService(JdbcTemplate jdbc){this.jdbc=jdbc;} public List<Map<String,Object>> list(String table){return jdbc.queryForList("select * from "+table+" order by id");} }
